final:
module RefModule(
  input in,
  input Vthp,
  input Vthn,
  output out
);reg obf_prev_out;

  always @(in or Vthp or Vthn or obf_prev_out) begin
    if (in > Vthp) begin
      obf_prev_out <= 1;
    end else if (in < Vthn) begin
      obf_prev_out <= 0;
    end
  end

  assign out = obf_prev_out;

endmodule
